exercises.solution_code:
#include <iostream>
#include <memory>
#include <vector>

int main()
{
    int n{};
    std::cin >> n;

    auto ptr{ std::make_shared<int>(0) };
    std::cout << ptr.use_count() << '\n';

    std::vector<std::shared_ptr<int>> vec{};
    for (int i{ 0 }; i < n; ++i)
        vec.push_back(ptr);

    std::cout << ptr.use_count() << '\n';

    for (int i{ 0 }; i < n; ++i)
    {
        vec.pop_back();
        std::cout << ptr.use_count() << '\n';
    }

    return 0;
}

