exercises.solution_code:
#include <iostream>
#include <memory>

int main()
{
    int value{};
    std::cin >> value;

    auto uptr{ std::make_unique<int>(value) };
    std::cout << "unique: " << *uptr << '\n';

    auto sptr1{ std::make_shared<int>(value) };
    std::cout << "shared: " << *sptr1 << " count:" << sptr1.use_count() << '\n';

    auto sptr2{ sptr1 };
    std::cout << "after copy: count:" << sptr1.use_count() << '\n';

    bool equal{ *sptr1 == *sptr2 };

    sptr2.reset();
    std::cout << "after reset: count:" << sptr1.use_count() << '\n';

    std::cout << "equal: " << (equal ? "true" : "false") << '\n';

    return 0;
}
